var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHILD_EXTRA_NULL_NULL","text":{"KOREA":"엄마, 나 이 약 먹으면 이제 기침 안 해?","JPN":"ママ、この薬を飲めば咳が止まるの？","ENG":"Mommy, am I going to stop coughing after I drink this syrup?","TWN":"媽媽，我把這個藥吃掉就不會咳嗽了嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MOTHER_EXTRA_NULL_NULL","text":{"KOREA":"그럼. 비 맞으면 안 되니까 어서 가자, 응?","JPN":"そうよ。雨に濡れると風邪を引いちゃうから、早く行きましょう。","ENG":"That's right, sweetie. Now let's hurry back home. We wouldn't want to get caught in the rain.","TWN":"是啊，不能淋到雨，我們快回去吧！"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHILD_EXTRA_NULL_NULL","text":{"KOREA":"응! 제프티 아저씨들이 아빠한테도 자랑하랬어!","JPN":"うん！　ジェフティのおじさんたちがパパにも自慢していいって言ったの！","ENG":"Okay! Those nice Jehuty uncles told me to tell daddy about them too!","TWN":"嗯！傑夫堤叔叔還叫我跟爸爸炫耀呢！"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>프로토타입들은 전부 자멸해 버렸어. 로그를 검토해 보니 기동 직후 자의적으로 합선을 일으켰더군.</color>","JPN":"<color=#ff3636>プロトタイプは全て自滅してしまった。ログを確認してみたら、起動直後に自分の意志でショートを起こしたそうだ。</color>","ENG":"<color=#ff3636>All the prototypes self-destructed. According to the log, they voluntarily short-circuited themselves immediately upon activation.</color>","TWN":"<color=#ff3636>樣品已經全都自行銷毀。 查看歷程，發現是啟動後隨機引起短路。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"하나 남아 있습니다. 성능도 우리가 원했던 기준을 충족하고 있어요.","JPN":"一つだけ残っています。性能も私たちが決めた基準を満たしています。","ENG":"There's still one left. And its performance more than meets the standards we desire.","TWN":"還剩一個，性能也符合我們想要的標準。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>저건 결함품이야. 탑재시켰다간 사람들한테 총구를 돌릴 결함품일 뿐이라고.</color>","JPN":"<color=#ff3636>あれは欠陥品だよ。搭載させると人々に銃口を向ける欠陥品にすぎない。</color>","ENG":"<color=#ff3636>That one's defective. I'll only put our people in danger if we load that thing up.</color>","TWN":"<color=#ff3636>那是瑕疵品。是搭載後會將槍口轉向人的瑕疵品。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"저건 사람과 다르지 않아요. 어떻게 가르치냐에 따라 충분히 교정할 수 있습니다.","JPN":"あれは人と同じです。教え方によって十分改善できます。","ENG":"But it's no different from a person. We can correct its behavior with ample education.","TWN":"她就跟人一樣，只要好好教她，是可以矯正的。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>우리가 왜 여기 모였는지 잊었나? 당장 폐기시켜!</color>","JPN":"<color=#ff3636>我々がここに集まった理由を忘れたのか？　今すぐ廃棄しろ！</color>","ENG":"<color=#ff3636>Did you forget why we're here in the first place? Get rid of it right away!</color>","TWN":"<color=#ff3636>你忘記我們爲什麼會在這裡嗎？立刻將她報廢！</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>우리가 사람을 만들려고 했나? 우리한테 필요한 건 무기야!</color>","JPN":"<color=#ff3636>人を作ろうとしたのではない！　我々に必要なものは武器だ！</color>","ENG":"<color=#ff3636>We're not trying to build a person! What we need is a weapon!</color>","TWN":"<color=#ff3636>我們想製造的是人嗎？我們需要的是武器！</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>사람들 대신 전쟁터에서 싸우다 죽어 줄 무기!</color>","JPN":"<color=#ff3636>人の代わりに戦場で戦い、死んでくれる武器なのだ！</color>","ENG":"<color=#ff3636>A weapon to fight and die in our stead on the battlefield!</color>","TWN":"<color=#ff3636>代替人類在戰場上戰死的武器！</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"호라이즌 파이낸스입니다.","JPN":"ホライズン・ファイナンスです。","ENG":"You've reached Horizon Finance.","TWN":"地平線金融。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"대출 상담은 현재 중단 중이니 다음에 다시 걸어 주십시오.","JPN":"現在貸付けの相談を行っておりません。また今度かけ直してください。","ENG":"We have currently suspended loan applications. Please call us at a later time.","TWN":"目前暫時不受理資金洽詢，請下次再打。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>이상하군요. 제 단말기를 방전시킬 만큼 연락하던 분은 그쪽이셨을 텐데요.</color>","JPN":"<color=#ffd34c>おかしいですね。私の端末を放電させるほど連絡してきたのはそちらだったと思いますが。</color>","ENG":"<color=#ffd34c>That's weird. I mean, you're the one who kept calling me 'til my battery ran out.</color>","TWN":"<color=#ffd34c>真奇怪，把我的電話打到快沒電的人應該是你吧？</color>"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……코핀 컴퍼니?","JPN":"……コフィンカンパニー？","ENG":"…Coffin Company?","TWN":"……科芬公司？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이제야 연락이 닿았군요. 왜 계속 답신이 없었습니까.","JPN":"やっと連絡が取れましたね。なぜ今まで返事がなかったのですか。","ENG":"So I've finally gotten through to you. What took you so long to respond?","TWN":"終於聯絡上，爲什麼一直不回電？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저희도 사업하면서 적을 많이 만든 입장입니다. 더 많은 적을 만들지도 모르는 결정에는 더 신중히 움직여야죠.","JPN":"こちらも事業をしながら敵をたくさん作ってしまった立場です。より多くの敵を作ってしまう可能性があるなら、慎重に動くべきでしょう。","ENG":"As you may understand, this line of business inevitably involves making a lot of enemies. Extra caution is warranted in making a decision that could get us even more enemies.","TWN":"我們在做生意的過程中也製造不少敵人，對於要不要製造更多敵人，當然要慎重考慮囉。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};